+/// Verify the QE Identity JSON signature against the signing certificate's public key.
+fn verify_qe_identity_signature(
+    qe_identity_json: &str,
+    qe_identity_signature: &[u8],
+    signing_cert: &[u8],
+) -> Result<(), Error> {
+    let cert = webpki::EndEntityCert::try_from(signing_cert)
+        .map_err(|_| Error::InvalidCertificate)?;
+
+    let public_key = cert.public_key();
+
+    // The QE Identity signature is an ECDSA-P256-SHA256 signature over the raw JSON body
+    let verify_alg = &signature::ECDSA_P256_SHA256_ASN1;
+    let public_key = signature::UnparsedPublicKey::new(verify_alg, public_key.as_ref());
+
+    public_key
+        .verify(qe_identity_json.as_bytes(), qe_identity_signature)
+        .map_err(|_| Error::InvalidQeIdentitySignature)?;
+
+    Ok(())
+}
+
+/// Verify the QE Report's MRSIGNER, ISVPRODID, and ISVSVN against the QE Identity collateral.
+fn verify_qe_report_against_identity(
+    qe_report: &QeReport,
+    qe_identity: &QeIdentity,
+) -> Result<(), Error> {
+    // Verify MRSIGNER matches the expected value from QE Identity
+    let expected_mrsigner = hex::decode(&qe_identity.mrsigner)
+        .map_err(|_| Error::InvalidQeIdentity)?;
+    if qe_report.mrsigner.as_ref() != expected_mrsigner.as_slice() {
+        return Err(Error::QeReportMrsignerMismatch);
+    }
+
+    // Verify ISVPRODID matches the expected value from QE Identity
+    if qe_report.isv_prod_id != qe_identity.isv_prod_id {
+        return Err(Error::QeReportIsvProdIdMismatch);
+    }
+
+    // Verify ISVSVN is at least the minimum required value from QE Identity
+    let min_isvsvn = qe_identity
+        .tcb_levels
+        .iter()
+        .filter(|tcb| tcb.tcb_status == TcbStatus::UpToDate || tcb.tcb_status == TcbStatus::SWHardeningNeeded)
+        .map(|tcb| tcb.tcb.isvsvn)
+        .min()
+        .unwrap_or(0);
+
+    if qe_report.isv_svn < min_isvsvn {
+        return Err(Error::QeReportIsvSvnTooLow);
+    }
+
+    // Verify miscselect against QE Identity mask
+    let expected_miscselect = qe_identity.miscselect & qe_identity.miscselect_mask;
+    if (qe_report.miscselect & qe_identity.miscselect_mask) != expected_miscselect {
+        return Err(Error::QeReportMiscselectMismatch);
+    }
+
+    // Verify attributes against QE Identity mask
+    let expected_attributes = qe_identity.attributes & qe_identity.attributes_mask;
+    if (qe_report.attributes & qe_identity.attributes_mask) != expected_attributes {
+        return Err(Error::QeReportAttributesMismatch);
+    }
+
+    Ok(())
+}
